package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

public class GsonBuilderTest {

  @Test
  public void testDisableHtmlEscaping() throws Exception {
    GsonBuilder builder = new GsonBuilder();

    // Initially escapeHtmlChars should be true (DEFAULT_ESCAPE_HTML)
    Field escapeHtmlCharsField = GsonBuilder.class.getDeclaredField("escapeHtmlChars");
    escapeHtmlCharsField.setAccessible(true);
    boolean initialValue = (boolean) escapeHtmlCharsField.get(builder);
    assertTrue(initialValue, "escapeHtmlChars should be true by default");

    // Call disableHtmlEscaping and check returned instance is same
    GsonBuilder returned = builder.disableHtmlEscaping();
    assertSame(builder, returned, "disableHtmlEscaping should return this");

    // Check escapeHtmlChars is now false
    boolean afterValue = (boolean) escapeHtmlCharsField.get(builder);
    assertFalse(afterValue, "escapeHtmlChars should be false after disableHtmlEscaping");
  }
}
